def begin(self, mode=None, bookmarks=None, metadata=None, timeout=None,
          db=None, imp_user=None, dehydration_hooks=None,
          hydration_hooks=None, **handlers):

    # Set default mode to WRITE if not specified
    if mode is None:
        mode = "WRITE"

    # Validate mode
    if mode not in ("READ", "WRITE"):
        raise ValueError("Mode must be either 'READ' or 'WRITE'")

    # Build extra parameters dict
    extra = {}
    if bookmarks:
        extra["bookmarks"] = list(bookmarks)
    if metadata:
        extra["metadata"] = metadata
    if timeout is not None:
        extra["timeout"] = timeout
    if db:
        extra["db"] = db
    if imp_user:
        extra["imp_user"] = imp_user

    # Add hooks if provided
    if dehydration_hooks:
        extra["dehydration_hooks"] = dehydration_hooks
    if hydration_hooks:
        extra["hydration_hooks"] = hydration_hooks

    # Create BEGIN message
    message = {
        "mode": mode
    }
    if extra:
        message.update(extra)

    # Add message to output queue and create Response
    self._append(("BEGIN", message))
    return Response(self._connection, **handlers)

def round_half_to_even(n):
    """
    Rounds a number according to round-half-to-even rules.
    For numbers exactly halfway between two integers, rounds to the nearest even number.
    For all other numbers, rounds to the nearest integer.
    """
    # If n is already an integer, return it
    if isinstance(n, int):
        return n

    # Get decimal part
    decimal = n - int(n)

    # If decimal is exactly 0.5
    if decimal == 0.5:
        # Round to nearest even number
        if int(n) % 2 == 0:
            return int(n)
        else:
            return int(n) + 1

    # For all other cases, round normally
    return round(n)

def point_type(name, fields, srid_map):
    """
    Dynamically create a Point subclass.
    """
    class_attrs = {
        '__slots__': tuple(fields),
        '_srid_map': srid_map
    }

    def __init__(self, *args, **kwargs):
        if len(args) > len(fields):
            raise TypeError(f"{name} takes {len(fields)} positional arguments but {len(args)} were given")

        # Set positional arguments
        for field, value in zip(fields, args):
            setattr(self, field, value)

        # Set keyword arguments
        for field, value in kwargs.items():
            if field not in fields:
                raise TypeError(f"{name} got an unexpected keyword argument '{field}'")
            if hasattr(self, field):
                raise TypeError(f"Got multiple values for argument '{field}'")
            setattr(self, field, value)

        # Check all fields are set
        for field in fields:
            if not hasattr(self, field):
                raise TypeError(f"Missing required argument: '{field}'")

    def __repr__(self):
        args = [f"{field}={getattr(self, field)!r}" for field in fields]
        return f"{name}({', '.join(args)})"

    def transform(self, srid):
        if srid not in self._srid_map:
            raise ValueError(f"Unknown SRID: {srid}")
        return self._srid_map[srid](self)

    class_attrs['__init__'] = __init__
    class_attrs['__repr__'] = __repr__
    class_attrs['transform'] = transform

    return type(name, (), class_attrs)

