def difference(d1, d2, level=-1):
    if level == 0:
        return {}

    result = {}

    # Handle keys in d1
    for key in d1:
        # If key not in d2, include entire value from d1
        if key not in d2:
            result[key] = d1[key]
        # If key in both but values differ
        elif d1[key] != d2[key]:
            # For nested dictionaries, recurse if level allows
            if isinstance(d1[key], dict) and isinstance(d2[key], dict) and level != 1:
                nested_diff = difference(d1[key], d2[key], level - 1 if level > 0 else -1)
                if nested_diff:
                    result[key] = nested_diff
            # For non-dict values or level=1, include if different
            elif d1[key] != d2[key]:
                result[key] = d1[key]

    return result

def generate_default_observer_schema_dict(manifest_dict, first_level=False):
    result = {}

    # Handle identifying fields at first level
    identifying_fields = ['apiVersion', 'kind', 'metadata']

    for key, value in manifest_dict.items():
        if first_level and key in identifying_fields:
            # Copy identifying fields as-is at first level
            result[key] = value
        elif isinstance(value, dict):
            # Recursively process nested dictionaries
            result[key] = generate_default_observer_schema_dict(value)
        elif isinstance(value, list):
            # Process lists using helper function
            from .utils import generate_default_observer_schema_list
            result[key] = generate_default_observer_schema_list(value)
        else:
            # Replace all other values with None
            result[key] = None

    return result

def update_last_applied_manifest_list_from_resp(
    last_applied_manifest, observer_schema, response
):
    # Handle empty response
    if not response:
        return

    # Ensure last_applied_manifest has enough elements
    while len(last_applied_manifest) < len(response):
        last_applied_manifest.append({})

    # Update each element in the list
    for i, (schema_item, resp_item) in enumerate(zip(observer_schema, response)):
        # Handle dict type schema
        if isinstance(schema_item, dict):
            if not isinstance(last_applied_manifest[i], dict):
                last_applied_manifest[i] = {}
            update_last_applied_manifest_dict_from_resp(
                last_applied_manifest[i], schema_item, resp_item
            )
        # Handle list type schema
        elif isinstance(schema_item, list):
            if not isinstance(last_applied_manifest[i], list):
                last_applied_manifest[i] = []
            update_last_applied_manifest_list_from_resp(
                last_applied_manifest[i], schema_item, resp_item
            )
        # Handle primitive types
        else:
            last_applied_manifest[i] = resp_item

def update_last_applied_manifest_dict_from_resp(
    last_applied_manifest, observer_schema, response
):
    """
    Together with :func:``update_last_applied_manifest_list_from_resp``, this
    function is called recursively to update a partial ``last_applied_manifest``
    from a partial Kubernetes response

    Args:
        last_applied_manifest (dict): partial ``last_applied_manifest`` being
            updated
        observer_schema (dict): partial ``observer_schema``
        response (dict): partial response from the Kubernetes API.

    Raises:
        KeyError: If the observed field is not present in the Kubernetes response
    """
    # Go through all fields in the observer schema
    for field, schema in observer_schema.items():
        # Skip if field is already in last_applied_manifest
        if field in last_applied_manifest:
            continue

        # Get value from response, raise KeyError if not found
        try:
            value = response[field]
        except KeyError:
            raise KeyError(f"Field {field} not found in Kubernetes response")

        # Handle nested dictionaries recursively
        if isinstance(schema, dict) and isinstance(value, dict):
            last_applied_manifest[field] = {}
            update_last_applied_manifest_dict_from_resp(
                last_applied_manifest[field], schema, value
            )

        # Handle lists recursively if schema is a dict
        elif isinstance(schema, dict) and isinstance(value, list):
            last_applied_manifest[field] = []
            update_last_applied_manifest_list_from_resp(
                last_applied_manifest[field], schema, value
            )

        # For simple values, copy directly
        else:
            last_applied_manifest[field] = value

def generate_default_observer_schema(app):
    """
    Generate the default observer schema for each Kubernetes resource present in
    ``spec.manifest`` for which a custom observer schema hasn't been specified.

    Args:
        app (krake.data.kubernetes.Application): The application for which to generate a
            default observer schema
    """
    # Initialize empty observer schema if none exists
    if not app.spec.observer:
        app.spec.observer = {}

    # Iterate through each manifest in the application spec
    for manifest in app.spec.manifest:
        # Get resource kind from manifest
        kind = manifest.get('kind')

        # Skip if kind not found
        if not kind:
            continue

        # Skip if observer schema already exists for this kind
        if kind in app.spec.observer:
            continue

        # Generate default schema based on resource kind
        default_schema = {
            'conditions': [{
                'type': 'Available',
                'status': 'True'
            }],
            'state': {
                'ready': {
                    'path': 'status.phase',
                    'value': 'Running'
                }
            }
        }

        # Add default schema to observer
        app.spec.observer[kind] = default_schema

