def validate(self, inventory, extract_spec_version=False):
    """
    Validate a given inventory.

    If extract_spec_version is True then will look at the type value to determine
    the specification version. In the case that there is no type value or it isn't
    valid, then other tests will be based on the version given in self.spec_version.
    """
    if not isinstance(inventory, dict):
        raise ValueError("Inventory must be a dictionary")

    # Extract spec version from type if requested
    if extract_spec_version:
        try:
            inv_type = inventory.get('type', '')
            if inv_type.startswith('inventory/'):
                self.spec_version = inv_type.split('/')[1]
        except (AttributeError, IndexError):
            pass

    # Validate required fields
    required_fields = ['id', 'type', 'items']
    for field in required_fields:
        if field not in inventory:
            raise ValueError(f"Missing required field: {field}")

    # Validate ID
    if not isinstance(inventory['id'], str):
        raise ValueError("ID must be a string")

    # Validate type
    if not isinstance(inventory['type'], str):
        raise ValueError("Type must be a string")
    if not inventory['type'].startswith('inventory/'):
        raise ValueError("Type must start with 'inventory/'")

    # Validate items
    if not isinstance(inventory['items'], list):
        raise ValueError("Items must be a list")

    # Validate each item in items
    for item in inventory['items']:
        if not isinstance(item, dict):
            raise ValueError("Each item must be a dictionary")

        # Check required item fields
        required_item_fields = ['id', 'count']
        for field in required_item_fields:
            if field not in item:
                raise ValueError(f"Item missing required field: {field}")

        # Validate item ID
        if not isinstance(item['id'], str):
            raise ValueError("Item ID must be a string")

        # Validate item count
        if not isinstance(item['count'], (int, float)):
            raise ValueError("Item count must be a number")
        if item['count'] < 0:
            raise ValueError("Item count cannot be negative")

    return True

def get_logical_path_map(inventory, version):
    """
    Get a map of logical paths in state to files on disk for version in inventory.

    Returns a dictionary: logical_path_in_state -> set(content_files)

    The set of content_files may includes references to duplicate files in
    later versions than the version being described.
    """
    logical_path_map = {}

    # Iterate through all versions up to and including target version
    for ver in range(version + 1):
        if ver in inventory:
            # For each file in this version
            for logical_path, content_files in inventory[ver].items():
                # Add or update the set of content files for this logical path
                if logical_path not in logical_path_map:
                    logical_path_map[logical_path] = set()
                logical_path_map[logical_path].update(content_files)

    return logical_path_map

def validate_fixity(self, fixity, manifest_files):
    """
    Validate fixity block in inventory.

    Check the structure of the fixity block and makes sure that only files
    listed in the manifest are referenced.
    """
    if not isinstance(fixity, dict):
        raise ValueError("Fixity block must be a dictionary")

    # Check each algorithm block
    for algorithm, checksums in fixity.items():
        if not isinstance(algorithm, str):
            raise ValueError("Fixity algorithm must be a string")

        if not isinstance(checksums, dict):
            raise ValueError(f"Checksums for {algorithm} must be a dictionary")

        # Validate each file checksum
        for filepath, checksum in checksums.items():
            if not isinstance(filepath, str):
                raise ValueError("File path must be a string")

            if not isinstance(checksum, str):
                raise ValueError("Checksum must be a string")

            # Check that file exists in manifest
            if filepath not in manifest_files:
                raise ValueError(f"File {filepath} in fixity block not found in manifest")

    return True

