def validate_hierarchy(self, validate_objects=True, check_digests=True, show_warnings=False):
    """
    Validate storage root hierarchy.

    Returns:
        num_objects - number of objects checked
        good_objects - number of objects checked that were found to be valid
    """
    num_objects = 0
    good_objects = 0

    # Walk through all directories recursively
    for root, dirs, files in os.walk(self.root_path):
        for file in files:
            file_path = os.path.join(root, file)
            num_objects += 1

            try:
                # Validate individual object if requested
                if validate_objects:
                    is_valid = True

                    # Check file exists and is readable
                    if not os.path.isfile(file_path):
                        is_valid = False
                        if show_warnings:
                            print(f"Warning: File {file_path} does not exist or is not accessible")

                    # Check file digest if requested
                    if check_digests and is_valid:
                        stored_digest = self._get_stored_digest(file_path)
                        calculated_digest = self._calculate_digest(file_path)

                        if stored_digest != calculated_digest:
                            is_valid = False
                            if show_warnings:
                                print(f"Warning: Digest mismatch for {file_path}")

                    if is_valid:
                        good_objects += 1
                else:
                    # If not validating, count all objects as good
                    good_objects += 1

            except Exception as e:
                if show_warnings:
                    print(f"Warning: Error validating {file_path}: {str(e)}")
                continue

    return num_objects, good_objects

def find_path_type(path):
    import os
    import glob

    # Check if path exists
    if not os.path.exists(path):
        return "Path does not exist"

    # Look for Namaste files matching 0=*
    namaste_files = glob.glob(os.path.join(path, "0=*"))

    if not namaste_files:
        if os.path.isfile(path):
            return "file"
        return "No Namaste files found"

    # Read first Namaste file content
    try:
        with open(namaste_files[0], 'r') as f:
            content = f.read().strip()

        # Check for OCFL Storage Root
        if content.startswith("ocfl_"):
            return "root"

        # Check for OCFL Object
        elif content.startswith("ocfl"):
            return "object"

    except Exception as e:
        return f"Error reading Namaste file: {str(e)}"

    return "Unknown Namaste file type"

