    else:
        # Validate other is a float
        if not isinstance(other, (int, float)):
            raise TypeError("Scale must be a number")

        # Get current scale
        current_scale = self.scale()

        # Check for zero scale
        if current_scale == 0:
            raise LenaValueError("Cannot rescale histogram with zero scale")

        # Rescale histogram values
        scale_factor = other / current_scale
        for key in self:
            self[key] *= scale_factor

        # Update stored scale
        self._scale = other

def scale(self, other=None):
    if other is None:
        return self._scale

    if not isinstance(other, (int, float)):
        raise TypeError("Scale must be a numeric value")

    if self._scale is None or self._scale == 0:
        raise LenaValueError("Cannot rescale graph with unknown or zero scale")

    # Get the last coordinate index
    last_coord_idx = len(self.coordinates) - 1
    if last_coord_idx < 0:
        return

    # Calculate scaling factor
    scale_factor = other / self._scale

    # Rescale the last coordinate values
    self.values[last_coord_idx] *= scale_factor

    # Rescale associated errors if they exist
    if hasattr(self, 'errors') and self.errors is not None:
        self.errors[last_coord_idx] *= scale_factor

    # Update the scale
    self._scale = other

def hist_to_graph(hist, make_value=None, get_coordinate="left",
                  field_names=("x", "y"), scale=None):
    # Default make_value function returns bin content
    if make_value is None:
        make_value = lambda x: x

    # Get coordinates based on specified method
    def get_bin_coordinate(bin):
        if get_coordinate == "left":
            return bin.left
        elif get_coordinate == "right":
            return bin.right
        elif get_coordinate == "middle":
            return (bin.left + bin.right) / 2
        else:
            raise ValueError("get_coordinate must be 'left', 'right' or 'middle'")

    # Create points list
    points = []
    for bin in hist:
        x = get_bin_coordinate(bin)
        y = make_value(bin.content)

        # Handle single value vs tuple return from make_value
        if isinstance(y, tuple):
            points.append((x,) + y)
        else:
            points.append((x, y))

    # Set scale if specified
    if scale is True:
        scale = hist.scale

    # Validate field names match point dimensions
    if len(field_names) != len(points[0]):
        raise ValueError(f"Number of field names ({len(field_names)}) must match point dimensions ({len(points[0])})")

    # Create and return graph
    from .graph import Graph
    return Graph(points, field_names=field_names, scale=scale)

def _verify(iface, candidate, tentative=False, vtype=None):
    from zope.interface.exceptions import Invalid
    from zope.interface.interface import Method
    from collections import defaultdict

    errors = defaultdict(list)

    # Check if candidate claims to provide interface
    if not tentative and not iface.providedBy(candidate):
        raise Invalid(f"{candidate!r} does not provide interface {iface!r}")

    # Check methods and attributes
    for name, desc in iface.namesAndDescriptions(all=True):
        if isinstance(desc, Method):
            # Verify method exists
            if not hasattr(candidate, name):
                errors['missing_methods'].append(name)
                continue

            method = getattr(candidate, name)
            if not callable(method):
                errors['not_callable'].append(name)
                continue

            # Verify method signature
            try:
                from inspect import signature
                impl_sig = signature(method)
                iface_sig = signature(desc)

                if impl_sig.parameters != iface_sig.parameters:
                    errors['wrong_signature'].append(name)
            except ValueError:
                # Can't get signature, skip verification
                pass

        else:
            # Verify attribute exists
            if not hasattr(candidate, name):
                errors['missing_attributes'].append(name)

    # Raise errors if any found
    if errors:
        messages = []
        if errors['missing_methods']:
            messages.append(f"Missing required methods: {', '.join(errors['missing_methods'])}")
        if errors['not_callable']:
            messages.append(f"Attributes that should be methods: {', '.join(errors['not_callable'])}")
        if errors['wrong_signature']:
            messages.append(f"Methods with wrong signatures: {', '.join(errors['wrong_signature'])}")
        if errors['missing_attributes']:
            messages.append(f"Missing required attributes: {', '.join(errors['missing_attributes'])}")

        if len(messages) == 1:
            raise Invalid(messages[0])
        else:
            raise Invalid('\n'.join(messages))

    return True

def verifyObject(iface, candidate, tentative=False):
    from zope.interface.exceptions import Invalid, DoesNotImplement, BrokenImplementation, BrokenMethodImplementation
    from zope.interface.interface import Method

    errors = []

    # Check if candidate claims to provide interface
    if not tentative and not iface.providedBy(candidate):
        errors.append(DoesNotImplement(iface))

    # Check methods and attributes
    for name, desc in iface.namesAndDescriptions(1):
        try:
            attr = getattr(candidate, name)
        except AttributeError:
            errors.append(BrokenImplementation(iface, name))
            continue

        # If it's a method, verify the signature
        if isinstance(desc, Method):
            if not callable(attr):
                errors.append(BrokenMethodImplementation(name, "Not callable"))
                continue

            # Check method signature using inspect
            import inspect
            try:
                impl_sig = inspect.signature(attr)
                iface_sig = desc.getSignatureInfo()

                # Compare required arguments
                impl_params = [p for p in impl_sig.parameters.values() 
                             if p.default == inspect.Parameter.empty and 
                             p.kind not in (inspect.Parameter.VAR_POSITIONAL, inspect.Parameter.VAR_KEYWORD)]

                if len(impl_params) < len(iface_sig.get('required', [])):
                    errors.append(BrokenMethodImplementation(name, "Incorrect number of required arguments"))

            except ValueError:
                # Can't get signature, skip detailed checking
                pass

    # If we have errors, raise them
    if errors:
        if len(errors) == 1:
            raise errors[0]
        raise Invalid(errors)

    return True

def verifyClass(iface, candidate, tentative=False):
    """
    Verify that the *candidate* might correctly provide *iface*.
    """
    # Get all attributes defined in the interface
    iface_attrs = dir(iface)

    # Get all attributes defined in the candidate class
    candidate_attrs = dir(candidate)

    # Check each required interface attribute
    for attr in iface_attrs:
        # Skip private/special attributes
        if attr.startswith('_'):
            continue

        # Check if attribute exists in candidate
        if attr not in candidate_attrs:
            if tentative:
                continue
            else:
                raise AttributeError(f"'{attr}' not found in candidate class")

        # Get interface and candidate attribute objects
        iface_attr = getattr(iface, attr)
        candidate_attr = getattr(candidate, attr)

        # Check if attributes are callable (methods)
        if callable(iface_attr):
            if not callable(candidate_attr):
                raise TypeError(f"'{attr}' must be callable")

            # Check method signature matches
            if not tentative:
                iface_sig = str(iface_attr.__code__.co_varnames)
                candidate_sig = str(candidate_attr.__code__.co_varnames)
                if iface_sig != candidate_sig:
                    raise TypeError(f"Method signature mismatch for '{attr}'")

    return True

def pop(self, key, default=__marker):
    """
    D.pop(k[,d]) -> v, remove specified key and return the corresponding value.
    If key is not found, d is returned if given, otherwise KeyError is raised.
    """
    try:
        value = self[key]
        del self[key]
        return value
    except KeyError:
        if default is __marker:
            raise
        return default

def _create_in_regex(self) -> Pattern:
    """
    Create the in-style parameter regular expression.

    Returns the in-style parameter regular expression (:class:`re.Pattern`).
    """
    # Match parameters in the format {param_name}
    return re.compile(r'{([^{}]+)}')

def _create_converter(self) -> _converting._Converter:
    """
    Create the parameter style converter.

    Returns the parameter style converter (:class:`._converting._Converter`).
    """
    return _converting._Converter(
        paramstyle=self.paramstyle,
        named_style=self.named_style
    )

def parse(self, timestr, default=None, ignoretz=False, tzinfos=None, **kwargs):
    """
    Parse the date/time string into a :class:`datetime.datetime` object.

    :param timestr: Any date/time string using the supported formats.
    :param default: The default datetime object, if this is a datetime object and not ``None``, 
                   elements specified in ``timestr`` replace elements in the default object.
    :param ignoretz: If set ``True``, time zones in parsed strings are ignored and a naive 
                    :class:`datetime.datetime` object is returned.
    :param tzinfos: Additional time zone names / aliases which may be present in the string.
    :param **kwargs: Keyword arguments as passed to ``_parse()``.
    :return: Returns a :class:`datetime.datetime` object or tuple with datetime and fuzzy tokens
    :raises: ParserError, TypeError, OverflowError
    """
    if not isinstance(timestr, str):
        raise TypeError("Parser must be given a string or character stream, not "
                      f"{type(timestr).__name__}")

    # Handle empty string
    if not timestr:
        raise ParserError("String is empty")

    try:
        # Parse the string using internal _parse method
        res, tokens = self._parse(timestr, **kwargs)

        # If no tokens found and fuzzy parsing not enabled, raise error
        if not tokens and not kwargs.get('fuzzy', False):
            raise ParserError("String does not contain a date.")

        # Build datetime object
        if res.year is None:
            res.year = default.year if default else datetime.now().year
        if res.month is None:
            res.month = default.month if default else 1
        if res.day is None:
            res.day = default.day if default else 1

        # Create aware or naive datetime based on ignoretz
        if res.tzname and not ignoretz:
            if tzinfos is not None:
                # Handle tzinfos dictionary or callable
                if isinstance(tzinfos, dict):
                    tz = tzinfos.get(res.tzname)
                else:
                    tz = tzinfos(res.tzname, res.tzoffset)
                if tz is None:
                    raise ParserError(f"Unknown timezone name: {res.tzname}")
            elif res.tzoffset:
                tz = datetime.timezone(datetime.timedelta(seconds=res.tzoffset))
            else:
                tz = None
        else:
            tz = None

        dt = datetime.datetime(
            res.year, res.month, res.day,
            res.hour if res.hour is not None else 0,
            res.minute if res.minute is not None else 0,
            res.second if res.second is not None else 0,
            res.microsecond if res.microsecond is not None else 0,
            tzinfo=tz
        )

        if kwargs.get('fuzzy_with_tokens', False):
            return dt, tokens
        else:
            return dt

    except (ValueError, OverflowError) as e:
        raise ParserError(str(e))

def fromutc(self, dt):
    """
    Given a timezone-aware datetime in a given timezone, calculates a
    timezone-aware datetime in a new timezone.

    Since this is the one time that we *know* we have an unambiguous
    datetime object, we take this opportunity to determine whether the
    datetime is ambiguous and in a "fold" state (e.g. if it's the first
    occurrence, chronologically, of the ambiguous datetime).

    :param dt:
        A timezone-aware :class:`datetime.datetime` object.
    """
    if dt.tzinfo is not self:
        dt = dt.replace(tzinfo=self)

    utc_offset = self._transition_info(dt.replace(fold=0))[0]
    dt_out = dt + utc_offset

    # Check if we're in a fold
    if self._fold_status(dt_out):
        return dt_out.replace(fold=1)
    else:
        return dt_out.replace(fold=0)

def identify_request(request: RequestType) -> bool:
    """
    Try to identify whether this is a Matrix request
    """
    # Check if request has Matrix-specific headers
    if 'Authorization' in request.headers:
        auth_header = request.headers['Authorization']
        if auth_header.startswith('Bearer'):
            # Matrix access tokens are typically Bearer tokens
            return True

    # Check for Matrix API endpoints
    if request.path.startswith('/_matrix/'):
        return True

    # Check for Matrix server name in host
    if request.host and '.matrix.' in request.host:
        return True

    # Check content type for Matrix-specific formats
    if request.content_type == 'application/json':
        try:
            body = request.get_json()
            # Check for common Matrix request fields
            if any(key in body for key in ['room_id', 'event_id', 'user_id', 'device_id']):
                return True
        except:
            pass

    return False

def format_dt(dt):
    """
    Format a datetime in the way that D* nodes expect.
    """
    return dt.strftime("%Y-%m-%d %H:%M:%S")

def fetch_content_type(url: str) -> Optional[str]:
    """
    Fetch the HEAD of the remote url to determine the content type.
    """
    import requests
    from typing import Optional

    try:
        response = requests.head(url, allow_redirects=True)
        return response.headers.get('content-type')
    except requests.RequestException:
        return None

def xml_children_as_dict(node):
    """
    Turn the children of node <xml> into a dict, keyed by tag name.

    This is only a shallow conversation - child nodes are not recursively processed.
    """
    result = {}
    for child in node:
        result[child.tag] = child
    return result

def get_nodeinfo_well_known_document(url, document_path=None):
    """
    Generate a NodeInfo .well-known document.

    See spec: http://nodeinfo.diaspora.software

    :arg url: The full base url with protocol, ie https://example.com
    :arg document_path: Custom NodeInfo document path if supplied (optional)
    :returns: dict
    """
    if not document_path:
        document_path = "/nodeinfo/2.0"

    # Remove trailing slash from url if present
    if url.endswith("/"):
        url = url[:-1]

    return {
        "links": [
            {
                "rel": "http://nodeinfo.diaspora.software/ns/schema/2.0",
                "href": f"{url}{document_path}"
            }
        ]
    }

def parse_diaspora_webfinger(document: str) -> Dict:
    """
    Parse Diaspora webfinger which is either in JSON format (new) or XRD (old).

    https://diaspora.github.io/diaspora_federation/discovery/webfinger.html
    """
    import json
    from xml.etree import ElementTree

    # Try parsing as JSON first (new format)
    try:
        data = json.loads(document)
        result = {
            'subject': data.get('subject', ''),
            'aliases': data.get('aliases', []),
            'links': []
        }

        # Parse links
        for link in data.get('links', []):
            if 'rel' in link and 'href' in link:
                result['links'].append({
                    'rel': link['rel'],
                    'href': link['href'],
                    'type': link.get('type', '')
                })
        return result

    except json.JSONDecodeError:
        # Try parsing as XRD (old format) 
        try:
            # Add XML namespace
            ns = {'xrd': 'http://docs.oasis-open.org/ns/xri/xrd-1.0'}

            root = ElementTree.fromstring(document)
            result = {
                'subject': '',
                'aliases': [],
                'links': []
            }

            # Get subject
            subject = root.find('xrd:Subject', ns)
            if subject is not None:
                result['subject'] = subject.text

            # Get aliases
            for alias in root.findall('xrd:Alias', ns):
                if alias.text:
                    result['aliases'].append(alias.text)

            # Get links
            for link in root.findall('xrd:Link', ns):
                link_data = {
                    'rel': link.get('rel', ''),
                    'href': link.get('href', ''),
                    'type': link.get('type', '')
                }
                result['links'].append(link_data)

            return result

        except ElementTree.ParseError:
            raise ValueError("Document is neither valid JSON nor valid XML")

def try_retrieve_webfinger_document(handle: str) -> Optional[str]:
    """
    Try to retrieve an RFC7033 webfinger document. Does not raise if it fails.
    """
    import requests
    from urllib.parse import urlparse, quote

    try:
        # Split handle into user and domain
        if '@' not in handle:
            return None
        user, domain = handle.split('@', 1)

        # Construct webfinger URL
        webfinger_url = f"https://{domain}/.well-known/webfinger"
        params = {
            'resource': f'acct:{quote(user)}@{domain}'
        }

        # Make request
        response = requests.get(webfinger_url, params=params, timeout=10)

        if response.status_code == 200:
            return response.text

    except (requests.RequestException, ValueError):
        pass

    return None

def retrieve_and_parse_diaspora_webfinger(handle):
    """
    Retrieve a and parse a remote Diaspora webfinger document.

    :arg handle: Remote handle to retrieve
    :returns: dict
    """
    import requests
    import xml.etree.ElementTree as ET
    from urllib.parse import urlparse

    # Split handle into user and host
    if '@' not in handle:
        raise ValueError("Handle must contain @")

    username, host = handle.split('@', 1)

    # Construct webfinger URL
    webfinger_url = f"https://{host}/.well-known/webfinger?resource=acct:{handle}"

    try:
        # Get the webfinger document
        response = requests.get(webfinger_url)
        response.raise_for_status()

        # Parse the response
        data = response.json()

        # Extract relevant information into a dict
        result = {
            'handle': handle,
            'host': host,
            'username': username,
            'links': {}
        }

        # Parse links
        for link in data.get('links', []):
            rel = link.get('rel', '')
            if rel:
                result['links'][rel] = {
                    'href': link.get('href', ''),
                    'type': link.get('type', '')
                }

        # Add additional properties if they exist
        if 'aliases' in data:
            result['aliases'] = data['aliases']
        if 'subject' in data:
            result['subject'] = data['subject']

        return result

    except requests.exceptions.RequestException as e:
        raise ConnectionError(f"Failed to retrieve webfinger document: {str(e)}")
    except ValueError as e:
        raise ValueError(f"Failed to parse webfinger document: {str(e)}")

def list_of_file_names(settings_dirs, spec_option):
    """
    Create a new IniType complex type
    """
    file_names = []

    # Handle single directory case
    if isinstance(settings_dirs, str):
        settings_dirs = [settings_dirs]

    # Iterate through all directories
    for directory in settings_dirs:
        # Handle spec option cases
        if spec_option.endswith('*'):
            # Get all files matching pattern
            base = spec_option[:-1]
            for file in os.listdir(directory):
                if file.startswith(base):
                    file_names.append(os.path.join(directory, file))
        else:
            # Get specific file
            file_path = os.path.join(directory, spec_option)
            if os.path.exists(file_path):
                file_names.append(file_path)

    return file_names

def ansible_config_manager(cls):
    """
    Gets the ansible config manager.
    """
    from ansible.config.manager import ConfigManager
    return ConfigManager()

def validate_from_content(cls, spec_content=None):
    """
    validates that spec (YAML) content has all required fields

    :param spec_content: content of spec file
    :raise IRValidatorException: when mandatory data
    is missing in spec file
    :return: Dictionary with data loaded from a spec (YAML) file
    """
    if spec_content is None:
        raise IRValidatorException("No spec content provided")

    try:
        # Try to load YAML content
        yaml_content = yaml.safe_load(spec_content)

        if not isinstance(yaml_content, dict):
            raise IRValidatorException("Spec content must be a dictionary")

        # Check for required fields
        required_fields = ['name', 'version', 'description']
        missing_fields = []

        for field in required_fields:
            if field not in yaml_content:
                missing_fields.append(field)

        if missing_fields:
            raise IRValidatorException(
                f"Missing mandatory fields in spec: {', '.join(missing_fields)}"
            )

        return yaml_content

    except yaml.YAMLError as e:
        raise IRValidatorException(f"Invalid YAML content: {str(e)}")

def validate_from_file(cls, yaml_file=None):
    """
    Loads & validates that a YAML file has all required fields

    :param yaml_file: Path to YAML file 
    :raise IRValidatorException: when mandatory data is missing in file
    :return: Dictionary with data loaded from a YAML file
    """
    try:
        import yaml

        if yaml_file is None:
            raise IRValidatorException("No YAML file path provided")

        with open(yaml_file, 'r') as f:
            yaml_data = yaml.safe_load(f)

        if not isinstance(yaml_data, dict):
            raise IRValidatorException("YAML file must contain a dictionary/mapping")

        # Validate required fields
        required_fields = ['name', 'version', 'description']  # Example required fields
        missing_fields = [field for field in required_fields if field not in yaml_data]

        if missing_fields:
            raise IRValidatorException(f"Missing mandatory fields in YAML: {', '.join(missing_fields)}")

        return yaml_data

    except yaml.YAMLError as e:
        raise IRValidatorException(f"Error parsing YAML file: {str(e)}")
    except IOError as e:
        raise IRValidatorException(f"Error reading YAML file: {str(e)}")
    except Exception as e:
        raise IRValidatorException(f"Unexpected error validating YAML file: {str(e)}")

class IRValidatorException(Exception):
    """Custom exception for YAML validation errors"""
    pass

def _include_groups(self, parser_dict):
    """
    Resolves the include dict directive in the spec files.
    """
    if not isinstance(parser_dict, dict):
        return parser_dict

    if 'include' in parser_dict:
        included_groups = parser_dict.pop('include')
        if not isinstance(included_groups, list):
            included_groups = [included_groups]

        for group in included_groups:
            if group in self.groups:
                parser_dict.update(self.groups[group])
            else:
                raise ValueError(f"Group '{group}' referenced in include directive not found")

    for value in parser_dict.values():
        if isinstance(value, dict):
            self._include_groups(value)

    return parser_dict

def get_spec_defaults(self):
    """
    Resolve arguments' values from spec and other sources.
    """
    defaults = {}

    if hasattr(self, 'spec') and self.spec:
        # Get default values from spec
        for param_name, param in self.spec.parameters.items():
            if param.default is not param.empty:
                defaults[param_name] = param.default

        # Get values from environment variables if specified
        if hasattr(self.spec, 'env_vars'):
            for param_name, env_var in self.spec.env_vars.items():
                if env_var in os.environ:
                    defaults[param_name] = os.environ[env_var]

        # Get values from config file if specified
        if hasattr(self.spec, 'config_file') and os.path.exists(self.spec.config_file):
            with open(self.spec.config_file) as f:
                config = json.load(f)
                for param_name, value in config.items():
                    defaults[param_name] = value

    return defaults

def get_deprecated_args(self):
    """
    Returning dict with options which deprecate others.
    """
    deprecated_args = {}
    for option in self.options:
        if hasattr(option, 'deprecated_options'):
            for deprecated in option.deprecated_options:
                deprecated_args[deprecated] = option.name
    return deprecated_args

def validate_arg_deprecation(self, cli_args, answer_file_args):
    """
    Validates and prints the deprecated arguments.

    :param cli_args: the dict of arguments from cli
    :param answer_file_args:  the dict of arguments from files
    """
    deprecated_args = {
        'arg_name': 'new_arg_name',  # Map of old arg names to new ones
    }

    # Check CLI args for deprecated arguments
    for old_arg, new_arg in deprecated_args.items():
        if old_arg in cli_args:
            print(f"Warning: Argument '{old_arg}' is deprecated. Please use '{new_arg}' instead.")

    # Check answer file args for deprecated arguments  
    for old_arg, new_arg in deprecated_args.items():
        if old_arg in answer_file_args:
            print(f"Warning: Argument '{old_arg}' in answer file is deprecated. Please use '{new_arg}' instead.")

def validate_requires_args(self, args):
    """
    Check if all the required arguments have been provided.
    """
    if not hasattr(self, 'required_args'):
        return True

    for required_arg in self.required_args:
        if required_arg not in args:
            return False

    return True

def validate_length_args(self, args):
    """
    Check if value of arguments is not longer than length specified.

    :param args: The received arguments.
    """
    for arg_name, arg_value in args.items():
        if hasattr(self, f'{arg_name}_length'):
            max_length = getattr(self, f'{arg_name}_length')
            if isinstance(arg_value, (str, list, dict, tuple)) and len(arg_value) > max_length:
                raise ValueError(f"Length of {arg_name} cannot exceed {max_length} characters")

def validate_choices_args(self, args):
    """
    Check if value of choice arguments is one of the available choices.

    :param args: The received arguments.
    """
    for arg_name, arg_value in args.items():
        if arg_name in self.choices:
            if arg_value not in self.choices[arg_name]:
                raise ValueError(f"Invalid choice '{arg_value}' for argument '{arg_name}'. "
                               f"Available choices are: {self.choices[arg_name]}")

def validate_min_max_args(self, args):
    """
    Check if value of arguments is between minimum and maximum values.

    :param args: The received arguments.
    """
    for arg_name, arg_value in args.items():
        if hasattr(self, f'min_{arg_name}') and hasattr(self, f'max_{arg_name}'):
            min_val = getattr(self, f'min_{arg_name}')
            max_val = getattr(self, f'max_{arg_name}')

            if not min_val <= arg_value <= max_val:
                raise ValueError(
                    f"Value for {arg_name} must be between {min_val} and {max_val}. "
                    f"Got {arg_value}"
                )

def create_complex_argumet_type(self, subcommand, type_name, option_name, spec_option):
    """
    Build the complex argument type

    :param subcommand: the command name
    :param type_name: the complex type name 
    :param option_name: the option name
    :param spec_option: option's specifications
    :return: the complex type instance
    """
    # Create a new class dynamically with the type name
    complex_type = type(type_name, (), {})

    # Add validation method
    def validate(cls, value):
        if not value:
            raise ValueError(f"Value required for {option_name}")

        # Handle different complex type validations based on spec_option
        if 'allowed_values' in spec_option:
            if value not in spec_option['allowed_values']:
                raise ValueError(f"Value {value} not in allowed values for {option_name}")

        if 'pattern' in spec_option:
            import re
            if not re.match(spec_option['pattern'], value):
                raise ValueError(f"Value {value} does not match pattern for {option_name}")

        if 'min_length' in spec_option:
            if len(value) < spec_option['min_length']:
                raise ValueError(f"Value {value} is shorter than minimum length for {option_name}")

        if 'max_length' in spec_option:
            if len(value) > spec_option['max_length']:
                raise ValueError(f"Value {value} is longer than maximum length for {option_name}")

        return value

    # Add string representation method
    def __str__(cls):
        return f"Complex argument type for {subcommand} {option_name}"

    # Add methods to the class
    setattr(complex_type, 'validate', classmethod(validate))
    setattr(complex_type, '__str__', classmethod(__str__))

    return complex_type

def merge_extra_vars(vars_dict, extra_vars=None):
    """
    Extend ``vars_dict`` with ``extra-vars``

    :param vars_dict: Dictionary to merge extra-vars into
    :param extra_vars: List of extra-vars
    """
    if not extra_vars:
        return vars_dict

    for var in extra_vars:
        if '=' not in var:
            continue

        key, value = var.split('=', 1)
        key = key.strip()
        value = value.strip()

        # Try to convert value to appropriate type
        try:
            # Try to convert to int
            value = int(value)
        except ValueError:
            try:
                # Try to convert to float
                value = float(value)
            except ValueError:
                # Handle boolean values
                if value.lower() == 'true':
                    value = True
                elif value.lower() == 'false':
                    value = False
                # Otherwise keep as string

        vars_dict[key] = value

    return vars_dict

def _convert_non_cli_args(self, parser_name, values_dict):
    """
    Casts arguments to correct types by modifying values_dict param.

    By default all the values are strings.

    :param parser_name: The command name, e.g. main, virsh, ospd, etc
    :param values_dict: The dict of with arguments
    """
    # Get parser configuration for this command
    parser_config = self.parser_config.get(parser_name, {})

    # Iterate through all arguments in values_dict
    for arg_name, value in values_dict.items():
        # Skip if value is None
        if value is None:
            continue

        # Get argument type from parser config
        arg_type = parser_config.get(arg_name, {}).get('type', str)

        try:
            # Convert boolean string values
            if arg_type == bool:
                if isinstance(value, str):
                    values_dict[arg_name] = value.lower() in ('true', 'yes', '1', 'on')
            # Convert numeric types        
            elif arg_type in (int, float):
                values_dict[arg_name] = arg_type(value)
            # Convert list types    
            elif arg_type == list:
                if isinstance(value, str):
                    values_dict[arg_name] = value.split(',')
            # Convert dict types        
            elif arg_type == dict:
                if isinstance(value, str):
                    try:
                        values_dict[arg_name] = eval(value)
                    except:
                        # If eval fails, try to parse as key=value pairs
                        pairs = value.split(',')
                        values_dict[arg_name] = dict(p.split('=') for p in pairs)

        except (ValueError, SyntaxError, TypeError):
            # If conversion fails, leave as original string value
            continue

def get_plugin_spec_flatten_dict(plugin_dir):
    """
    Creates a flat dict from the plugin spec

    :param plugin_dir: A path to the plugin's dir
    :return: A flatten dictionary contains the plugin's properties
    """
    flattened_dict = {}

    try:
        # Read and parse plugin spec file
        spec_file = os.path.join(plugin_dir, 'plugin.spec')
        if not os.path.exists(spec_file):
            return flattened_dict

        with open(spec_file, 'r') as f:
            spec_data = yaml.safe_load(f)

        def flatten_dict(d, parent_key=''):
            items = []
            for k, v in d.items():
                new_key = f"{parent_key}.{k}" if parent_key else k

                if isinstance(v, dict):
                    items.extend(flatten_dict(v, new_key).items())
                else:
                    items.append((new_key, v))
            return dict(items)

        # Flatten the nested dictionary
        if spec_data and isinstance(spec_data, dict):
            flattened_dict = flatten_dict(spec_data)

    except Exception as e:
        # Return empty dict if any error occurs
        pass

    return flattened_dict

